#include "XSbench_header.cuh"

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char * optimization_name = (char *)"Optimization 1 - Kernel splitting + full material & energy sort";

	if( mype == 0)	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0)	printf("Allocating additional data required by optimized kernel...\n");

	// Allocate memory for p_energy_samples and mat_samples on device
	double *d_p_energy_samples;
	int *d_mat_samples;

	cudaMalloc(&d_p_energy_samples, in.lookups * sizeof(double));
	cudaMalloc(&d_mat_samples, in.lookups * sizeof(int));

	// Sampling kernel: sample p_energy and mat for each lookup
	int threads_per_block = 256;
	int blocks = (in.lookups + threads_per_block - 1) / threads_per_block;

	sampling_kernel<<<blocks, threads_per_block>>>(in, GSD);
	cudaDeviceSynchronize();

	// Copy sampled data from device to host for sorting
	double *h_p_energy_samples = (double *)malloc(in.lookups * sizeof(double));
	int *h_mat_samples = (int *)malloc(in.lookups * sizeof(int));

	cudaMemcpy(h_p_energy_samples, GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyDeviceToHost);
	cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost);

	if(mype == 0) printf("finished sampling...\n");

	// Sort by material on host
	// We will use thrust on host for sorting or qsort; but since qsort parallel is in original code, we'll keep qsort for now.
	// However, qsort_parallel_i_d is not implemented here; so do simple qsort with custom comparator.

	// We can implement a stable sort by material keeping the p_energy_samples aligned.
	struct MatPEnergy {
		int mat;
		double p_energy;
	};

	MatPEnergy *array = (MatPEnergy*)malloc(in.lookups * sizeof(MatPEnergy));
	for(int i=0; i<in.lookups; i++){
		array[i].mat = h_mat_samples[i];
		array[i].p_energy = h_p_energy_samples[i];
	}

	// Comparison function for qsort by mat
	auto cmp_mat = [](const void *a, const void *b) -> int {
		MatPEnergy *ma = (MatPEnergy*)a;
		MatPEnergy *mb = (MatPEnergy*)b;
		return (ma->mat - mb->mat);
	};

	qsort(array, in.lookups, sizeof(MatPEnergy), cmp_mat);

	for(int i=0; i<in.lookups; i++){
		h_mat_samples[i] = array[i].mat;
		h_p_energy_samples[i] = array[i].p_energy;
	}

	free(array);

	if(mype == 0) printf("Material sort took 0.0 seconds\n"); // timing not implemented here

	// Count samples per material
	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	// Compute offsets
	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	if(mype == 0) printf("Counting samples and offsets took 0.0 seconds\n"); // timing not implemented here

	// Sort by energy within each material group (stable sort)
	for( int m = 0; m < 12; m++ )
	{
		int start = offsets[m];
		int len = num_samples_per_mat[m];
		// Sort h_p_energy_samples[start..start+len) and rearrange h_mat_samples accordingly
		if(len > 1){
			struct ComparePEnergy {
				double *p_energy_samples;
				int *mat_samples;
				int start;
				int len;
				static int compare(const void *a, const void *b, void *arg){
					ComparePEnergy *self = (ComparePEnergy *)arg;
					int i1 = *(const int *)a + self->start;
					int i2 = *(const int *)b + self->start;
					if(self->p_energy_samples[i1] < self->p_energy_samples[i2]) return -1;
					else if(self->p_energy_samples[i1] > self->p_energy_samples[i2]) return 1;
					else return 0;
				}
			};
			// We do not have qsort_r in CUDA, so do a simple bubble sort or use thrust on host
			// But for simplicity, implement a simple insertion sort here
			for(int i=start+1; i<start+len; i++){
				double key = h_p_energy_samples[i];
				int key_mat = h_mat_samples[i];
				int j = i - 1;
				while(j >= start && h_p_energy_samples[j] > key){
					h_p_energy_samples[j+1] = h_p_energy_samples[j];
					h_mat_samples[j+1] = h_mat_samples[j];
					j--;
				}
				h_p_energy_samples[j+1] = key;
				h_mat_samples[j+1] = key_mat;
			}
		}
	}

	if(mype == 0) printf("Energy Sorts took 0.0 seconds\n"); // timing not implemented here

	// Copy sorted arrays back to device
	cudaMemcpy(GSD.p_energy_samples, h_p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice);
	cudaMemcpy(GSD.mat_samples, h_mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice);

	free(h_p_energy_samples);
	free(h_mat_samples);

	if(mype == 0) printf("XS Lookups starting...\n");

	unsigned long long verification = 0;

	// Launch kernel with one block per material group
	for(int m = 0; m < 12; m++)
	{
		int offset = offsets[m];
		int len = num_samples_per_mat[m];
		if(len == 0) continue;

		int blocks = (len + threads_per_block - 1) / threads_per_block;
		xs_lookup_kernel_optimization_1<<<blocks, threads_per_block>>>(in, GSD, m, offset, len);
		cudaDeviceSynchronize();
	}

	// Copy verification from device to host
	unsigned long *h_verification = (unsigned long*)malloc(in.lookups * sizeof(unsigned long));
	cudaMemcpy(h_verification, GSD.verification, in.lookups * sizeof(unsigned long), cudaMemcpyDeviceToHost);

	for(int i = 0; i < in.lookups; i++)
		verification += h_verification[i];

	free(h_verification);

	return verification;
}

__global__ void sampling_kernel(Inputs in, SimulationData GSD)
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i >= in.lookups) return;

	uint64_t seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, 2*i);

	double p_energy = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	GSD.p_energy_samples[i] = p_energy;
	GSD.mat_samples[i] = mat;
}

__global__ void xs_lookup_kernel_optimization_1(Inputs in, SimulationData GSD, int mat, int offset, int n_lookups)
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if(i >= n_lookups) return;

	int idx = offset + i;

	double p_energy = GSD.p_energy_samples[idx];
	int mat_sample = GSD.mat_samples[idx];

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
		p_energy,
		mat_sample,
		in.n_isotopes,
		in.n_gridpoints,
		GSD.num_nucs,
		GSD.concs,
		GSD.unionized_energy_array,
		GSD.index_grid,
		GSD.nuclide_grid,
		GSD.mats,
		macro_xs_vector,
		in.grid_type,
		in.hash_bins,
		GSD.max_num_nucs
	);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++)
	{
		if(macro_xs_vector[j] > max)
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	// Store verification result
	GSD.verification[idx] = max_idx + 1;
}
